exercises.solution_code:
#include <iostream>

long long power(int base, int exp) {
    if (exp == 0)
        return 1;
    if (exp % 2 == 1)
        return base * power(base, exp - 1);
    long long half = power(base, exp / 2);
    return half * half;
}

int main() {
    int base, exp;
    std::cin >> base >> exp;
    std::cout << power(base, exp) << '\n';
    return 0;
}
